    // B	    van den Boele
    // BP	    van den Boele - de Vries
    // P	    de Vries
    // PB	    de Vries - van den Boele

    let nameFormatted = '';

    switch (convention) {
        case "B":
            if (typeof middleName !== 'undefined' && middleName) { nameFormatted = nameFormatted + ' ' + middleName }
